@app.route('/cancel_reservation/<int:reservation_id>', methods=['GET'])
def cancel_reservations(reservation_id):
    reservations = load_reservations()
    # We have to mark the reservation status as "Cancelled" or remove it?
    # Spec does not clarify cancelling status field, original spec only mentions statuses: Upcoming, Completed
    # We'll assume removal of reservation or status changed to "Cancelled" (not in original statuses but logical)
    # To keep consistency, we remove the reservation from file

    updated_reservations = []
    removed = False
    for r in reservations:
        try:
            if int(r['reservation_id']) == reservation_id and r['username'] == CURRENT_USERNAME:
                # skip (remove) this reservation
                removed = True
                continue
        except:
            pass
        updated_reservations.append(r)

    if removed:
        try:
            with open(os.path.join(DATA_DIR, 'reservations.tx'), 'w') as f:
                for r in updated_reservations:
                    line = ','.join([
                        r['reservation_id'], r['username'], r['guest_name'], r['phone'], r['email'],
                        r['party_size'], r['date'], r['time'], r['special_requests'], r['status']
                    ])
                    f.write(line + '\n')
        except Exception as e:
            return f"Failed to update reservations: {str(e)}", 500

    # Redirect back to my reservations page or dashboard
    return redirect(url_for('my_reservationss'))

@app.route('/waitlist', methods=['GET', 'POST'])
def wait_list():
    if request.method == 'GET':
        # join waitlist form with party_size
        party_size = request.args.get('party_siz')
        if party_size:
            # Add to waitlist
            waitlist = load_waitlist()
            max_id = 0
            for w in waitlist:
                try:
                    wid = int(w['waitlist_id'])
                    if wid > max_id:
                        max_id = wid
                except:
                    continue
            new_id = str(max_id + 1)
            join_time = datetime.now().strftime('%m-%d-%Y %H:%M:%S')
            new_entry = {
                'waitlist_id': new_id,
                'username': CURRENT_USERNAME,
                'party_size': party_size,
                'join_time': join_time,
                'status': 'Active'
            }
            waitlist.append(new_entry)
            # Save back
            try:
                with open(os.path.join(DATA_DIR, 'waitlist.tx'), 'w') as f:
                    for w in waitlist:
                        line = ','.join([
                            w['waitlist_id'], w['username'], w['party_size'], w['join_time'], w['status']
                        ])
                        f.write(line + '\n')
            except Exception as e:
                return f"Failed to add to waitlist: {str(e)}", 500
            return redirect(url_for('wait_list'))
        else:
            # Show user's position in waitlist
            waitlist = load_waitlist()
            # filter only active waitlist
            active_waitlist = [w for w in waitlist if w['status'] == 'Active']
            # Sort by join_time ascending
            active_waitlist.sort(key=lambda x: datetime.strptime(x['join_time'], '%m-%d-%Y %H:%M:%S'))
            position = None
            for idx, w in enumerate(active_waitlist, start=1):
                if w['username'] == CURRENT_USERNAME:
                    position = str(idx)
                    break
            return render_template('waitlist.htm', position=position)

    else:  # POST
        # POST form not defined in spec for waitlist, treat same as GET for joining
        # though spec says GET to join waitlist passing party_size
        return redirect(url_for('wait_list'))

