@app.route('/profile', methods=['GET', 'POST'])
def profil():
    users = load_users()
    user = users.get(CURRENT_USERNAME)
    if not user:
        return "User not found", 404

    if request.method == 'GET':
        # Send profile dict {username, email}
        profile = {
            'username': user['username'],
            'email': user['email']
        }
        return render_template('profile.htm', profile=profile)

    # POST: update email
    new_email = request.form.get('emails')
    if not new_email:
        return "Email is required", 400

    # Update user email in file
    users_updated = []
    try:
        with open(os.path.join(DATA_DIR, 'users.tx'), 'r') as f:
            for line in f:
                parts = line.strip().split(',')
                if len(parts) == 4:
                    uname = parts[0]
                    email = parts[1]
                    phone = parts[2]
                    full_name = parts[3]
                    if uname == CURRENT_USERNAME:
                        email = new_email
                    users_updated.append((uname, email, phone, full_name))
    except FileNotFoundError:
        return "Users file not found", 500

    try:
        with open(os.path.join(DATA_DIR, 'users.tx'), 'w') as f:
            for u in users_updated:
                f.write(','.join(u) + '\n')
    except Exception as e:
        return f"Failed to update profile: {str(e)}", 500

    # Redirect to profile page
    return redirect(url_for('profil'))

